#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code)
# =============================================================================
"""
Step ID: step02
Step Name: compute_calibration
RQ: results/ch6/6.9.7
Generated: 2026-01-19

PURPOSE:
Compute calibration scores as z(confidence) - z(accuracy) with within-paradigm
standardization to isolate trajectory shapes while removing baseline paradigm
difficulty differences.

EXPECTED INPUTS:
  - results/ch6/6.9.7/data/step01_merged_calibration_data.csv
    Columns: ['composite_ID', 'UID', 'test', 'paradigm', 'theta_accuracy', 'theta_confidence', 'TSVR_hours']
    Expected rows: 1200

EXPECTED OUTPUTS:
  - results/ch6/6.9.7/data/step02_calibration_scores.csv
    Columns: All previous + ['z_accuracy', 'z_confidence', 'calibration']
    Expected rows: 1200
  - results/ch6/6.9.7/data/step02_descriptive_stats.csv
    Columns: ['paradigm', 'test', 'n', 'mean_calibration', 'sd_calibration', 'outlier_count']
    Expected rows: 12 (3 paradigms × 4 timepoints)

VALIDATION CRITERIA:
  - Within-paradigm standardization: mean ≈ 0, SD ≈ 1 for each paradigm
  - No NaN or infinite values in calibration scores
  - Outliers (|calibration| > 3) < 5% of data

g_code REASONING:
- Approach: Group by paradigm, compute z-scores within each group using scipy.stats.zscore
- Why this approach: Preserves temporal trajectories while removing baseline differences
- Data flow: Raw theta scores → within-paradigm z-scores → calibration difference
- Expected performance: ~5 seconds (z-score computation)

IMPLEMENTATION NOTES:
- Analysis tool: scipy.stats.zscore from stdlib
- Validation tool: validate_standardization from tools.validation
- Parameters: axis=0 (columnwise), ddof=0 (population SD), nan_policy='raise'
- Calibration interpretation: 0=perfect, positive=overconfidence, negative=underconfidence
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy.stats import zscore
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import validation tool
from tools.validation import validate_standardization

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.7
LOG_FILE = RQ_DIR / "logs" / "step02_compute_calibration.log"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
    print(msg)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 2: compute_calibration")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: Merged accuracy and confidence data (1200 rows)

        log("[LOAD] Loading merged calibration data from Step 1...")

        input_path = RQ_DIR / "data" / "step01_merged_calibration_data.csv"
        df = pd.read_csv(input_path, encoding='utf-8')
        log(f"[LOADED] {input_path.name} ({len(df)} rows, {len(df.columns)} cols)")

        # =========================================================================
        # STEP 2: Within-Paradigm Z-Standardization
        # =========================================================================
        # Compute z-scores separately for each paradigm across all timepoints
        # This preserves temporal trajectories within paradigm while normalizing baselines

        log("[STANDARDIZE] Computing within-paradigm z-scores...")

        # Function to compute z-scores within group
        def standardize_within_paradigm(group):
            """Compute z-scores for theta_accuracy and theta_confidence within paradigm."""
            group['z_accuracy'] = zscore(group['theta_accuracy'], ddof=0, nan_policy='raise')
            group['z_confidence'] = zscore(group['theta_confidence'], ddof=0, nan_policy='raise')
            return group

        # Apply standardization by paradigm
        df = df.groupby('paradigm', group_keys=False).apply(standardize_within_paradigm)

        log(f"[STANDARDIZED] Z-scores computed for 3 paradigms")

        # Verify standardization by paradigm
        log("[VERIFY] Checking standardization quality by paradigm:")
        for paradigm in df['paradigm'].unique():
            paradigm_data = df[df['paradigm'] == paradigm]
            mean_acc = paradigm_data['z_accuracy'].mean()
            std_acc = paradigm_data['z_accuracy'].std(ddof=0)
            mean_conf = paradigm_data['z_confidence'].mean()
            std_conf = paradigm_data['z_confidence'].std(ddof=0)

            log(f"  {paradigm}:")
            log(f"    z_accuracy: mean={mean_acc:.6f}, SD={std_acc:.6f}")
            log(f"    z_confidence: mean={mean_conf:.6f}, SD={std_conf:.6f}")

            # Check if within tolerance (mean ~ 0, SD ~ 1)
            if abs(mean_acc) > 0.01 or abs(std_acc - 1.0) > 0.01:
                log(f"[WARNING] z_accuracy standardization off for {paradigm}")
            if abs(mean_conf) > 0.01 or abs(std_conf - 1.0) > 0.01:
                log(f"[WARNING] z_confidence standardization off for {paradigm}")

        # =========================================================================
        # STEP 3: Compute Calibration Scores
        # =========================================================================
        # calibration = z_confidence - z_accuracy
        # Values near 0 = good calibration (confidence matches accuracy)

        log("[COMPUTE] Computing calibration = z_confidence - z_accuracy...")

        df['calibration'] = df['z_confidence'] - df['z_accuracy']

        log(f"[COMPUTED] Calibration scores for {len(df)} observations")
        log(f"  Range: [{df['calibration'].min():.3f}, {df['calibration'].max():.3f}]")
        log(f"  Mean: {df['calibration'].mean():.3f}, SD: {df['calibration'].std():.3f}")

        # Check for NaN or infinite values
        nan_count = df['calibration'].isna().sum()
        inf_count = np.isinf(df['calibration']).sum()
        if nan_count > 0 or inf_count > 0:
            log(f"[ERROR] Invalid calibration values: NaN={nan_count}, Inf={inf_count}")
            sys.exit(1)

        log("[PASS] No invalid calibration values")

        # =========================================================================
        # STEP 4: Validate Standardization
        # =========================================================================

        log("[VALIDATE] Running standardization validation...")

        validation_result = validate_standardization(
            df,
            column_names=['z_accuracy', 'z_confidence'],
            tolerance=0.01
        )

        if not validation_result.get('valid', False):
            log(f"[ERROR] Standardization validation failed: {validation_result.get('message', 'Unknown error')}")
            sys.exit(1)

        log(f"[PASS] Standardization validated: {validation_result.get('message', 'OK')}")

        # =========================================================================
        # STEP 5: Compute Descriptive Statistics by Paradigm × Time
        # =========================================================================

        log("[DESCRIPTIVE] Computing statistics by paradigm × timepoint...")

        desc_stats = df.groupby(['paradigm', 'test']).agg(
            n=('calibration', 'count'),
            mean_calibration=('calibration', 'mean'),
            sd_calibration=('calibration', 'std'),
            min_calibration=('calibration', 'min'),
            max_calibration=('calibration', 'max')
        ).reset_index()

        # Identify outliers (|calibration| > 3) per cell
        def count_outliers(group):
            return (np.abs(group['calibration']) > 3).sum()

        outlier_counts = df.groupby(['paradigm', 'test']).apply(count_outliers).reset_index(name='outlier_count')
        desc_stats = desc_stats.merge(outlier_counts, on=['paradigm', 'test'])

        log(f"[COMPUTED] Descriptive statistics: {len(desc_stats)} cells (3 paradigms × 4 times)")

        # Check overall outlier proportion
        total_outliers = desc_stats['outlier_count'].sum()
        outlier_pct = (total_outliers / len(df)) * 100
        log(f"[INFO] Total outliers (|calibration| > 3): {total_outliers} ({outlier_pct:.2f}%)")

        if outlier_pct > 5.0:
            log(f"[WARNING] Outlier proportion exceeds 5% threshold")
        else:
            log("[PASS] Outlier proportion acceptable (< 5%)")

        # Display descriptive statistics
        log("[INFO] Descriptive statistics by paradigm × time:")
        for _, row in desc_stats.iterrows():
            log(f"  {row['paradigm']}, {row['test']}: n={row['n']}, mean={row['mean_calibration']:.3f}, SD={row['sd_calibration']:.3f}, outliers={row['outlier_count']}")

        # =========================================================================
        # STEP 6: Save Outputs
        # =========================================================================

        log("[SAVE] Saving calibration scores and descriptive statistics...")

        # Save full calibration dataset
        calibration_out = RQ_DIR / "data" / "step02_calibration_scores.csv"
        df.to_csv(calibration_out, index=False, encoding='utf-8')
        log(f"[SAVED] {calibration_out.name} ({len(df)} rows, {len(df.columns)} cols)")

        # Save descriptive statistics
        desc_out = RQ_DIR / "data" / "step02_descriptive_stats.csv"
        desc_stats.to_csv(desc_out, index=False, encoding='utf-8')
        log(f"[SAVED] {desc_out.name} ({len(desc_stats)} rows)")

        log("[SUCCESS] Step 2 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
